import { format, isValid } from 'date-fns';
import { utcToZonedTime, zonedTimeToUtc } from 'date-fns-tz';

import type { DateValue } from './Calendar.types';
import { ISO_FORMAT_PATTERN } from './constants';

/** Преобразование UTC->TZ. Если timeZone не задана, возвращаем копию originalUTC. */
export const convertUtcToTz = (originalUTC: Date, timeZone?: string): Date => {
	if (!timeZone) {
		return new Date(originalUTC);
	}
	return utcToZonedTime(originalUTC, timeZone);
};

/** Преобразование TZ->UTC. Если timeZone не задана, считаем, что zonedDate уже UTC. */
export const convertTzToUtc = (zonedDate: Date, timeZone?: string): Date => {
	if (!timeZone) {
		return new Date(zonedDate);
	}
	return zonedTimeToUtc(zonedDate, timeZone);
};

/** Проверка, что строка – это валидная ISO-дата (минимум "YYYY-MM-DD"). */
export const isValidDateString = (date: string): boolean => {
	const parsed = Date.parse(date);
	return ISO_FORMAT_PATTERN.test(date) && !Number.isNaN(parsed);
};

/** Превращаем ISO-строку в Date(UTC). Если некорректно, возвращаем null. */
export const getDateFromIsoString = (date: string): Date | null => {
	if (!date) {
		return null;
	}
	const isoDate = new Date(date);
	return isValid(isoDate) ? isoDate : null;
};

export const isRangeMode = <T>(value: T | T[]): value is T[] => Array.isArray(value);

/** Возвращаем Date(UTC) для value. Если не получилось, вернём new Date() (UTC now). */
export const getViewDate = (value: DateValue): Date => {
	if (isRangeMode(value)) {
		const first = value[0];
		const parsed = getDateFromIsoString(first);
		return parsed || new Date();
	}
	const parsed = getDateFromIsoString(value);
	return parsed || new Date();
};

/** Форматируем Date(UTC) в нужном формате, напр. "yyyy-MM-dd'T'HH:mm:ss'Z'". */
export const formatToISO = (dateUTC: Date, outputDateFormat: string): string => format(dateUTC, outputDateFormat);

/** Валидируем customViewDate (строка -> Date(UTC) или null). */
export const validateCustomViewDate = (date?: string): Date | null => {
	if (!date) {
		return null;
	}
	const iso = new Date(date);
	return isValid(iso) ? iso : null;
};

/** Проверяем, вышла ли checkedDate за пределы [minDate, maxDate], все в UTC. */
/**
 * Нормализуем дату к полуночи по UTC, сравнение выполняется только по году/месяцу/дню.
 * Это устраняет смещения по часовым поясам и off-by-one ошибки при проверке min/max.
 */
const normalizeToUtcMidnight = (d: Date | null): Date | null => {
	if (!d || Number.isNaN(d.getTime())) {
		return null;
	}
	return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
};

export const hasDateLimit = (checkedDate: Date | null, minDate: Date | null, maxDate: Date | null): boolean => {
	const cd = normalizeToUtcMidnight(checkedDate);
	const min = normalizeToUtcMidnight(minDate);
	const max = normalizeToUtcMidnight(maxDate);

	if (!cd) {
		return false;
	}
	if (min && cd < min) {
		return true;
	}
	if (max && cd > max) {
		return true;
	}
	return false;
};

/** Сравниваем две даты (UTC) по году, месяцу, числу. */
export const isSameDates = (d1: Date, d2: Date): boolean =>
	d1.getUTCFullYear() === d2.getUTCFullYear() &&
	d1.getUTCMonth() === d2.getUTCMonth() &&
	d1.getUTCDate() === d2.getUTCDate();

/** Сравниваем два месяца (UTC) (год и месяц). */
export const isSameMonths = (d1: Date, d2: Date): boolean =>
	d1 && d2 && d1.getUTCFullYear() === d2.getUTCFullYear() && d1.getUTCMonth() === d2.getUTCMonth();

/** Проверяем валидность времени (val) в заданном диапазоне timeRange. Возвращаем true, если НЕвалидно. */
export const isTimeValid = (
	val: { hours: string; minutes: string },
	timeRange: [string, string] = ['00:00', '23:59'],
): boolean => {
	const [h, m] = [+val.hours, +val.minutes];
	const [minH, minM] = timeRange[0].split(':').map(Number);
	const [maxH, maxM] = timeRange[1].split(':').map(Number);

	// isInRange === true, если внутри диапазона
	const isInRange = (h > minH || (h === minH && m >= minM)) && (h < maxH || (h === maxH && m <= maxM));

	// Возвращаем true, если время вышло за диапазон => невалидно.
	return !isInRange;
};

/**
 * Возвращаем массив недель (каждая неделя – 7 чисел или null) для указанного локального года/месяца.
 * @param localYear Год
 * @param localMonth Месяц
 * @param showAdjacentMonthDays Объект с настройками отображения дней соседних месяцев
 */
export const getWeeksOfMonth = (
	localYear: number,
	localMonth: number,
	showAdjacentMonthDays?: { showPrevious?: boolean; showNext?: boolean },
): Array<Array<{ day: number | null; month: number; year: number } | null>> => {
	// Локальная логика (в JS new Date(year, month, day) – локальная).
	// Но если нужно строгое ISO поведение, можно усложнить.

	// 1) найдём, какой день недели у первого числа (0=вс,1=пн,...)
	const firstDate = new Date(localYear, localMonth, 1);
	let startDay = firstDate.getDay(); // 0 (вс) ... 6 (сб)
	// Но в России обычно пн=1,... Вс=0 => возможно, стоит сдвигать.

	// Чтобы пн был первым (WEEKDAYS=["Пн","Вт",...,"Вс"]), сделаем небольшой трюк:
	// Если startDay=0 (вс), считаем, что это 7:
	if (startDay === 0) {
		startDay = 7;
	}

	// Сколько дней в месяце?
	const daysInMonth = new Date(localYear, localMonth + 1, 0).getDate();

	// Получаем информацию о предыдущем месяце
	const prevMonth = localMonth === 0 ? 11 : localMonth - 1;
	const prevYear = localMonth === 0 ? localYear - 1 : localYear;
	const daysInPrevMonth = new Date(prevYear, prevMonth + 1, 0).getDate();

	// Получаем информацию о следующем месяце
	const nextMonth = localMonth === 11 ? 0 : localMonth + 1;
	const nextYear = localMonth === 11 ? localYear + 1 : localYear;

	const weeks: Array<Array<{ day: number | null; month: number; year: number } | null>> = [];
	let currentDay = 1;
	// считаем максимум 6 недель
	for (let w = 0; w < 6; w++) {
		const weekRow = Array.from({ length: 7 }).fill(null) as Array<{
			day: number | null;
			month: number;
			year: number;
		} | null>;
		for (let d = 0; d < 7; d++) {
			// Первая неделя (w=0): начнём с (startDay-1) как сдвиг
			if (w === 0 && d < startDay - 1) {
				// Дни предыдущего месяца
				if (showAdjacentMonthDays?.showPrevious) {
					const prevMonthDay = daysInPrevMonth - (startDay - 2 - d);
					weekRow[d] = { day: prevMonthDay, month: prevMonth, year: prevYear };
				} else {
					weekRow[d] = null;
				}
			} else if (currentDay > daysInMonth) {
				// Дни следующего месяца
				if (showAdjacentMonthDays?.showNext) {
					const nextMonthDay = currentDay - daysInMonth;
					weekRow[d] = { day: nextMonthDay, month: nextMonth, year: nextYear };
					currentDay++;
				} else {
					weekRow[d] = null;
				}
			} else {
				// Дни текущего месяца
				weekRow[d] = { day: currentDay, month: localMonth, year: localYear };
				currentDay++;
			}
		}
		weeks.push(weekRow);
		// Если все дни текущего месяца уже отображены и не нужно показывать дни следующего месяца
		if (currentDay > daysInMonth && !showAdjacentMonthDays?.showNext) {
			break;
		}
		// Если все дни текущего месяца отображены и последняя неделя полностью заполнена
		if (w > 0 && currentDay > daysInMonth && weekRow.every(cell => cell !== null)) {
			break;
		}
	}
	return weeks;
};

/** Простой хелпер для генерации диапазона лет. */
export const getYearsRange = (startYear: number, endYear: number): number[] => {
	const arr: number[] = [];
	for (let y = startYear; y <= endYear; y++) {
		arr.push(y);
	}
	return arr;
};

/**
 * Сдвиг месяца влево/вправо (delta=-1 или +1) без мутаций исходной даты.
 * Сохраняет день месяца, если он существует в целевом месяце, иначе клемпит до последнего дня.
 * Возвращает новую дату в UTC.
 */
export const shiftMonthUTC = (viewDateUTC: Date, timeZone: string, delta: number, enableTimePicker: boolean): Date => {
	// Локальное представление для календарной арифметики
	const localView = enableTimePicker
		? convertUtcToTz(viewDateUTC, timeZone)
		: new Date(Date.UTC(viewDateUTC.getUTCFullYear(), viewDateUTC.getUTCMonth(), viewDateUTC.getUTCDate()));

	const currentDay = localView.getDate();
	const targetMonthIndex = localView.getMonth() + delta;
	const targetYear = localView.getFullYear() + Math.floor(targetMonthIndex / 12);
	const normalizedMonth = ((targetMonthIndex % 12) + 12) % 12;
	const lastDay = new Date(targetYear, normalizedMonth + 1, 0).getDate();
	const targetDay = Math.min(currentDay, lastDay);

	if (enableTimePicker) {
		const targetLocal = new Date(
			targetYear,
			normalizedMonth,
			targetDay,
			localView.getHours(),
			localView.getMinutes(),
			0,
			0,
		);
		return convertTzToUtc(targetLocal, timeZone);
	}

	return new Date(Date.UTC(targetYear, normalizedMonth, targetDay));
};
